INSERT INTO sys_oper_log (
    oper_user_id, oper_user_name, oper_module, oper_type,
    oper_content, oper_ip, oper_time
) VALUES (
             #{operUserId}, #{operUserName}, #{operModule}, #{operType},
             #{operContent}, #{operIp}, #{operTime}
         )

mapper.select:
SELECT * FROM sys_oper_log
WHERE oper_user_id = #{operUserId}
ORDER BY oper_time DESC

SELECT * FROM sys_oper_log
WHERE oper_module = #{operModule}
ORDER BY oper_time DESC

SELECT * FROM sys_oper_log
WHERE oper_type = #{operType}
ORDER BY oper_time DESC

SELECT * FROM sys_oper_log
WHERE oper_ip = #{operIp}
ORDER BY oper_time DESC

SELECT * FROM sys_oper_log
WHERE oper_time BETWEEN #{startTime} AND #{endTime}
ORDER BY oper_time DESC

SELECT * FROM sys_oper_log
ORDER BY oper_time DESC
    LIMIT #{limit} OFFSET #{offset}

SELECT * FROM sys_oper_log
WHERE 1=1

    AND oper_user_name LIKE CONCAT('%', #{operUserName}, '%')


    AND oper_module = #{operModule}


    AND oper_type = #{operType}


    AND oper_time >= #{startTime}


    AND oper_time <= #{endTime}

ORDER BY oper_time DESC

SELECT COUNT(1) FROM sys_oper_log
WHERE 1=1

    AND oper_user_name LIKE CONCAT('%', #{operUserName}, '%')


    AND oper_module = #{operModule}


    AND oper_type = #{operType}


    AND oper_time >= #{startTime}


    AND oper_time <= #{endTime}

SELECT * FROM sys_oper_log
ORDER BY oper_time DESC
    LIMIT #{limit}
